import { describe, it, expect } from "vitest";
import { runScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  // ----- Quote: base premiums -----
  it.todo("empty item list -> premium 5 G (only the processing fee)");
  it.todo("single sword (no modifiers, 0 years) -> 100 + 10 first + 5 fee = 115 G");
  it.todo("single amulet (no modifiers, 0 years) -> 60 + 6 + 5 = 71 G");
  it.todo("single staff (no modifiers, 0 years) -> 80 + 8 + 5 = 93 G");
  it.todo("single potion (no modifiers, 0 years) -> 40 + 4 + 5 = 49 G");

  // ----- Quote: components -----
  it.todo("2 runes -> base premium 50 G (no block)");
  it.todo("3 runes -> base premium 60 G (block applies)");
  it.todo("4 runes -> base premium 100 G (no block, block requires exactly 3)");
  it.todo("7 runes -> base premium 175 G");
  it.todo("2 runes + 1 moonstone -> base premium 75 G (no block: different types)");
  it.todo("3 runes + 3 moonstones -> base premium 120 G (two separate blocks)");

  // ----- Quote: individual modifiers -----
  it.todo("cursed sword (0 years, first insurance) -> 165 G (integration example)");
  it.todo("high-enchantment sword (enchantment 5, 0 years) -> 100 + 30 + 10 + 5 = 145 G");
  it.todo("sword with enchantment 4 -> no high-enchantment surcharge (115 G)");
  it.todo("long-standing customer with exactly 2 years -> loyalty discount applies");
  it.todo("customer with 1 year -> no loyalty discount");

  // ----- Quote: modifier scope on multi-item policies -----
  it.todo("cursed sword + plain amulet -> 160 base + 50 curse = 210 + first-insurances + fee");

  // ----- Quote: rounding in MHPCO's favor -----
  it.todo("premium calc yielding 197.5 G -> 198 G (rounded up)");

  // ----- Quote: integration examples -----
  it.todo("newcomer with cursed sword -> 165 G");
  it.todo("long-standing customer second contract: cursed sword enchant 7 -> 160 G");

  // ----- Quote: edge cases -----
  it.todo("quote with unknown item type -> non-zero exit, error to stderr, no results to stdout");

  // ----- Claim: basic -----
  it.todo("regular sword (steel, ench 3), damage 500 -> payout 400 (full - 100 deductible)");
  it.todo("damage to a rune (value 250), damage 200 -> payout 100 (full - 100 deductible)");

  // ----- Claim: special clauses -----
  it.todo("dragon-material sword, ench 9, damage 1000 -> payout 400 (50% wins, then deductible)");
  it.todo("dragon-material sword, ench 5, damage 800 -> payout 700 (dragon only, full - deductible)");
  it.todo("steel sword, ench 9, damage 1000 -> payout 400 (high-enchant only, 50% then deductible)");
  it.todo("dragon-material sword, ench 8, damage 1000 -> payout 400 (high-ench applies, then deductible)");

  // ----- Claim: deductible per item -----
  it.todo("dragon attack damages sword (500) and amulet (300) -> payout 600 (deductible per item)");

  // ----- Claim: multiple items of the same type -----
  it.todo("policy with two swords, two sword damages -> each treated separately with its own deductible");
  it.todo("more sword damages than swords insured -> non-zero exit, error to stderr");

  // ----- Claim: cap -----
  it.todo("policy with sword and amulet -> insurance sum 1600, cap 3200");
  it.todo("cursed sword (premium 165 with modifiers) -> cap 2000 (based on unmodified insurance value)");
  it.todo("policy with sword and 3 runes (block) -> insurance sum 1750 (block doesn't affect sum)");
  it.todo("sword cap 2000, two claims 1500 each -> first payout 1400 cap 600, second payout 600 cap 0");

  // ----- Claim: rounding -----
  it.todo("payout calc yielding 350.5 -> 350 G (rounded down, in MHPCO's favor)");

  // ----- Claim: edge cases -----
  it.todo("claim references damage entry for item not in policy -> non-zero exit, error to stderr");
  it.todo("claim with damage amount -200 -> non-zero exit, error to stderr");
});

