interface Item {
  type: string;
}

interface QuoteStep {
  op: "quote";
  items: Item[];
}

interface Scenario {
  customer: { yearsWithMHPCO: number };
  steps: QuoteStep[];
}

const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
};

function quotePremium(items: Item[]): number {
  let base = 0;
  for (const item of items) {
    const itemBase = BASE_PREMIUMS[item.type] ?? 0;
    base += itemBase + itemBase * 0.1; // first-insurance surcharge per item
  }
  return Math.ceil(base) + 5;
}

export function runScenario(input: unknown): unknown {
  const scenario = input as Scenario;
  const results = scenario.steps.map((step) => ({
    premium: quotePremium(step.items),
  }));
  return { results };
}

