input.content:
interface Item {
  type: string;
}

interface QuoteStep {
  op: "quote";
  items: Item[];
}

interface Scenario {
  customer: { yearsWithMHPCO: number };
  steps: QuoteStep[];
}

const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
  moonstone: 25,
};

const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
const BLOCK_SIZE = 3;
const BLOCK_PRICE = 60;

function itemBasePremium(item: Item): number {
  return BASE_PREMIUMS[item.type] ?? 0;
}

function componentsBase(items: Item[]): number {
  // group components by type, apply block-of-3 special price
  const counts: Record<string, number> = {};
  for (const item of items) {
    counts[item.type] = (counts[item.type] ?? 0) + 1;
  }
  let total = 0;
  for (const [type, count] of Object.entries(counts)) {
    if (count === BLOCK_SIZE) {
      total += BLOCK_PRICE;
    } else {
      total += count * BASE_PREMIUMS[type];
    }
  }
  return total;
}

function quotePremium(items: Item[]): number {
  const components = items.filter((i) => COMPONENT_TYPES.has(i.type));
  const mainItems = items.filter((i) => !COMPONENT_TYPES.has(i.type));

  let base = 0;
  for (const item of mainItems) {
    base += itemBasePremium(item);
  }
  base += componentsBase(components);

  // first-insurance surcharge: +10% per item-base
  // For block components, the surcharge is on the block base (60), not on individual components.
  // We compute it as 10% of total base for now (works because every item is a "first insurance")
  const firstInsurance = base * 0.1;

  return Math.ceil(base + firstInsurance) + 5;
}

export function runScenario(input: unknown): unknown {
  const scenario = input as Scenario;
  const results = scenario.steps.map((step) => ({
    premium: quotePremium(step.items),
  }));
  return { results };
}

