input.content:
interface Item {
  type: string;
  material?: string;
  enchantment?: number;
  cursed?: boolean;
}

interface QuoteStep {
  op: "quote";
  items: Item[];
}

interface Scenario {
  customer: { yearsWithMHPCO: number };
  steps: QuoteStep[];
}

const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
  moonstone: 25,
};

const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
const BLOCK_SIZE = 3;
const BLOCK_PRICE = 60;
const CURSE_SURCHARGE = 0.5;

interface ItemContribution {
  base: number;
  item: Item;
}

function isComponent(item: Item): boolean {
  return COMPONENT_TYPES.has(item.type);
}

/**
 * Compute the per-item base contributions, applying the component block discount.
 * For block components, the block price (60) is distributed evenly across the 3 components.
 */
function itemContributions(items: Item[]): ItemContribution[] {
  // Group components by type to detect blocks.
  const componentsByType: Record<string, Item[]> = {};
  for (const item of items) {
    if (isComponent(item)) {
      (componentsByType[item.type] ??= []).push(item);
    }
  }

  const contributions: ItemContribution[] = [];
  for (const item of items) {
    if (isComponent(item)) continue;
    contributions.push({ base: BASE_PREMIUMS[item.type] ?? 0, item });
  }

  for (const [type, group] of Object.entries(componentsByType)) {
    const perItemBase =
      group.length === BLOCK_SIZE ? BLOCK_PRICE / BLOCK_SIZE : BASE_PREMIUMS[type];
    for (const item of group) {
      contributions.push({ base: perItemBase, item });
    }
  }
  return contributions;
}

function itemSpecificMultiplier(item: Item): number {
  let multiplier = 1;
  if (item.cursed) multiplier += CURSE_SURCHARGE;
  return multiplier;
}

function quotePremium(items: Item[]): number {
  const contributions = itemContributions(items);
  let total = 0;
  for (const { base, item } of contributions) {
    const itemAdjusted = base * itemSpecificMultiplier(item);
    const firstInsurance = base * 0.1;
    total += itemAdjusted + firstInsurance;
  }
  return Math.ceil(total) + 5;
}

export function runScenario(input: unknown): unknown {
  const scenario = input as Scenario;
  const results = scenario.steps.map((step) => ({
    premium: quotePremium(step.items),
  }));
  return { results };
}

