function quotePremium(items: Item[]): number {
  const contributions = itemContributions(items);
  let total = 0;
  for (const { base, item } of contributions) {
    const itemAdjusted = base * itemSpecificMultiplier(item);
    const firstInsurance = base * 0.1;
    total += itemAdjusted + firstInsurance;
  }
  return Math.ceil(total) + 5;
}

